= \underbrace{\sideset{^\textcolor{Blue}{\boldsymbol{A}}}{_\textcolor{Orange}{\boldsymbol{B}}}{\begin{bmatrix}
\cos{\textcolor{Plum}{\theta}} & -\sin{\textcolor{Plum}{\theta}} \\ \sin{\textcolor{Plum}{\theta}} & \cos{\textcolor{Plum}{\theta}}
\end{bmatrix}}}_{\textsf{Matriz de rotacion} ~\boldsymbol{R}(\textcolor{Plum}{\theta}) }
\sideset{^\textcolor{Orange}{\boldsymbol{B}}}{}{\begin{bmatrix} \textcolor{ForestGreen}{p_{{x}}}  \\  \textcolor{ForestGreen}{p_{{y}}} \end{bmatrix}}
\]
\[
{}^\textcolor{Blue}{\boldsymbol{A}}{\textcolor{ForestGreen}{\boldsymbol{p}}} = {}^\textcolor{Blue}{\boldsymbol{A}}\boldsymbol{T}_{\textcolor{Orange}{\boldsymbol{B}}} {}^{\textcolor{Orange}{\boldsymbol{B}}}{\textcolor{ForestGreen}{\boldsymbol{p}}}
