\underbrace{{\begin{bmatrix} \colorbox{white}{1} & \colorbox{white}{0} & \colorbox{white}{$\textcolor{ForestGreen}{{t_x}}$} \\ \colorbox{white}{0} & \colorbox{white}{1} & \colorbox{white}{$\textcolor{ForestGreen}{{t_y}}$} \\ \colorbox{white}{0} & \colorbox{white}{0} & \colorbox{white}{1} \end{bmatrix}}}_{\textsf{Matriz de traslación} ~\textcolor{Blue}{{}^\boldsymbol{A}}\boldsymbol{T}_\textcolor{Orange}{\boldsymbol{B}} }
\begin{bmatrix} \textcolor{Orange}{p_{{x}_\boldsymbol{B}}}  \\  \textcolor{Orange}{p_{{y}_\boldsymbol{B}}} \\ {1}  \end{bmatrix} =
\begin{bmatrix} \textcolor{ForestGreen}{{t_x}} + \textcolor{Orange}{p_{{x}_\boldsymbol{B}}} \\ \colorbox{white}{$\textcolor{ForestGreen}{{t_y}} + \textcolor{Orange}{p_{{y}_\boldsymbol{B}}}$} \\ \colorbox{white}{1}  \end{bmatrix}
\end{align}
\]

Traslación y rotación 2D
\[
{}^\textcolor{Blue}{\boldsymbol{A}}{\boldsymbol{p}} = {}^\textcolor{Blue}{\boldsymbol{A}}\boldsymbol{R}_\textcolor{Orange}{\boldsymbol{B}} {}^\textcolor{Orange}{\boldsymbol{B}}{\boldsymbol{p}} +  {}^\textcolor{Blue}{\boldsymbol{A}}\boldsymbol{t}_{\textcolor{Orange}{\boldsymbol{B}}}
\]

\[
\begin{bmatrix} \textcolor{Blue}{p_{{x}_\boldsymbol{A}}}  \\  \textcolor{Blue}{p_{{y}_\boldsymbol{A}}}  \end{bmatrix} =
{\begin{bmatrix} \cos{\theta} & -\sin{\theta} \\ \sin{\theta} & \cos{\theta} \end{bmatrix}}  \begin{bmatrix} \textcolor{Orange}{p_{{x}_\boldsymbol{B}}}  \\  \textcolor{Orange}{p_{{y}_\boldsymbol{B}}}  \end{bmatrix} +
\begin{bmatrix} \textcolor{ForestGreen}{{t_x}}  \\  \textcolor{ForestGreen}{{t_y}}  \end{bmatrix}
\]


En coordenadas homogéneas: 
\[
\begin{bmatrix} \textcolor{Blue}{p_{{x}_\boldsymbol{A}}}  \\  \textcolor{Blue}{p_{{y}_\boldsymbol{A}}} \\ 1  \end{bmatrix} =
\left[
\begin{array}{cc|c}
\cos{\theta} & -\sin{\theta} & \textcolor{ForestGreen}{{t_x}} \\ \sin{\theta} & \cos{\theta} & \textcolor{ForestGreen}{{t_y}} \\ \hline 0 & 0 & 1
\end{array}
\right]
%{\begin{bmatrix} \cos{\theta} & -\sin{\theta} & \textcolor{ForestGreen}{{t_x}} \\ \sin{\theta} & \cos{\theta} & \textcolor{ForestGreen}{{t_y}} \\ 0 & 0 & 1 \end{bmatrix}}
\begin{bmatrix} \textcolor{Orange}{p_{{x}_\boldsymbol{B}}}  \\  \textcolor{Orange}{p_{{y}_\boldsymbol{B}}} \\ 1 \end{bmatrix}
\]


\[
\begin{bmatrix} \textcolor{Blue}{p_{{x}_\boldsymbol{A}}}  \\  \textcolor{Blue}{p_{{y}_\boldsymbol{A}}} \\ 1  \end{bmatrix} =
\left[
\begin{array}{c|c}
\begin{array}{c}  {}^\textcolor{Blue}{\boldsymbol{A}}\boldsymbol{R}_\textcolor{Orange}{\boldsymbol{B}} \end{array} & \begin{array}{c} {}^\textcolor{Blue}{\boldsymbol{A}}\boldsymbol{t}_{\textcolor{Orange}{\boldsymbol{B}}} \end{array} \\
\hline
\begin{array}{c} 0 & 0 \end{array} & 1
\end{array}
\right]
%{\begin{bmatrix} \cos{\theta} & -\sin{\theta} & \textcolor{ForestGreen}{{t_x}} \\ \sin{\theta} & \cos{\theta} & \textcolor{ForestGreen}{{t_y}} \\ 0 & 0 & 1 \end{bmatrix}}
\begin{bmatrix} \textcolor{Orange}{p_{{x}_\boldsymbol{B}}}  \\  \textcolor{Orange}{p_{{y}_\boldsymbol{B}}} \\ 1 \end{bmatrix}
\]

Generalizando
La estructura de \(\boldsymbol{T}\) se puede generalizar para \(n\)-dimensiones:
\[
\boldsymbol{T} ~\boldsymbol{\hat{p}} = \begin{bmatrix} \boldsymbol{R}_{n \times n} & \boldsymbol{t}_{n \times 1} \\ \boldsymbol{0}_{1 \times n} & 1 \end{bmatrix}_{(n+1) \times (n+1)} \boldsymbol{{p}}_{(n+1)}
\]
En resumen: a partir de la función no lineal de traslación-rotación, se desarrolló una función lineal en el sistema de coordenadas homogéneo \(\boldsymbol{\tilde{p}}\) \[
\begin{align*}
f(\boldsymbol{p}) &= \boldsymbol{R} ~\boldsymbol{p} + \boldsymbol{t} \\
&\downarrow \\
g(\boldsymbol{\tilde{p}}) &= \boldsymbol{T} \boldsymbol{\tilde{p}} =  \begin{bmatrix} {}^A\boldsymbol{R}_B & {}^A\boldsymbol{t}_B \\ \boldsymbol{0} & 1 \end{bmatrix} \tilde{p}
\end{align*}
\]

Composición de poses


\[
{}^\textcolor{Blue}{\boldsymbol{A}} \boldsymbol{\xi}_\textcolor{ForestGreen}{\boldsymbol{C}} =
{}^\textcolor{Blue}{\boldsymbol{A}} \boldsymbol{\xi}_\textcolor{Maroon}{\boldsymbol{B}} \otimes {}^\textcolor{Maroon}{\boldsymbol{B}} \boldsymbol{\xi}_\textcolor{ForestGreen}{\boldsymbol{C}}
\]
Se puede cacular como: \[
{}^\textcolor{Blue}{\boldsymbol{A}} \boldsymbol{\xi}_\textcolor{Maroon}{\boldsymbol{B}} \otimes {}^\textcolor{Maroon}{\boldsymbol{B}} \boldsymbol{\xi}_\textcolor{ForestGreen}{\boldsymbol{C}} =
{}^\textcolor{Blue}{\boldsymbol{A}} \boldsymbol{T}_\textcolor{Maroon}{\boldsymbol{B}} {}^\textcolor{Maroon}{\boldsymbol{B}} \boldsymbol{T}_\textcolor{ForestGreen}{\boldsymbol{C}}
\]


Dada la forma particular de \(\boldsymbol{T}\), el producto se puede obtener mediante:

\[
\begin{align}
\boldsymbol{\xi}_1 \otimes \boldsymbol{\xi}_2 &=
\begin{pmatrix} \boldsymbol{R}_1 & \boldsymbol{t}_1 \\ \boldsymbol{0} & 1 \end{pmatrix}
\begin{pmatrix} \boldsymbol{R}_2 & \boldsymbol{t}_2 \\ \boldsymbol{0} & 1 \end{pmatrix} \\[0.5em]
&= \begin{pmatrix} \boldsymbol{R}_1 \boldsymbol{R}_2 & \boldsymbol{t}_1 + \boldsymbol{R}_1 \boldsymbol{t}_2 \\ \boldsymbol{0} & 1 \end{pmatrix}
\end{align}
\]

